/** Map of slug → CityData for O(1) lookups */
export const CITY_MAP = new Map(US_CITIES.map((c) => [c.slug, c]));

/** Validate whether a slug corresponds to a known city */
export function isValidCitySlug(slug: string): boolean {
  return CITY_MAP.has(slug);
}

/** Get city data by slug */
export function getCityBySlug(slug: string): CityData | undefined {
  return CITY_MAP.get(slug);
}

/** Convert a city name to a URL-friendly slug */
export function cityNameToSlug(name: string): string {
  return name
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .trim();
}
